#define GAME_DURATION   136     // seconds
#define BLINK_START     16      // last N seconds

#define GAME_ROWS       48
#define GAME_COLS       160

#define COL_ROAD        "\033[48;2;0;80;0m"
#define COL_BORDER      "\033[48;2;40;80;160m"
#define COL_RESET       "\033[0m"
#define COL_PCCAR       "\033[48;2;160;50;0m"
#define COL_ENCAR       "\033[48;2;40;80;140m"
#define GOTO            "\033[%d;%dH"
#define CLEAR_SCRN      "\033[2J\033[H"

#define MAX_ENEMIES     1
#define DX_SCALE        4
#define BORDER_W        12      // border width in cells
#define PCAR_W          16      // player car width in cells
#define ENCAR_W         20      // enemy car width in cells
#define CAR_H           8
#define CRASHED_TIMER   20
#define SPEED_MAX       127
#define SPEED_STEP      4
#define DRIFT_TICKS     10
#define SPAWN_MARGIN    4
#define MID_LANE        ((GAME_COLS/2+BORDER_W)/2)
#define SILENCE_LIMIT   10      // frames before a held key clears (~700ms at 25fps)
                                // must exceed OS initial key-repeat delay (~500ms)
#define SND_RATE  8000
#define SND_CHUNK (SND_RATE / 15)   // one frame at 15fps = 533 samples

static int snd_pipe  = -1;
static int snd_prev_score = 0;


typedef struct {
    int x, y, crashed;
} PlayerCar;

typedef struct {
    int x, y, speed_acc, drift_timer, dx;  // dx: lateral drift direction
} EnemyCar;

typedef struct {
    PlayerCar pc;
    EnemyCar  enemies[MAX_ENEMIES];
    int score, elapsed;
} GameState;

typedef struct {
    const int  *data;
    int   w, h;
    const char *color;
} Sprite;

static GameState g = {  // initialize game state
    .pc         = {20, 35, 0},
    .enemies    = {{12, -10, 0, 0, 0}},
};

static struct termios orig;
static int fire_held;

