static Sprite pccar_sprite = {*pccar_data,  8, 8, COL_PCCAR};
static Sprite encar_sprite = {*encar_data, 10, 8, COL_ENCAR};
static Sprite crash_sprite = {*crash_data,  8, 8, COL_PCCAR};

