static int term_init(void) {
    if (tcgetattr(STDIN_FILENO, &orig) < 0) return -1;
    struct termios raw = orig;
    raw.c_lflag   &= ~(ICANON | ECHO);
    raw.c_cc[VMIN] = 0;
    if (tcsetattr(STDIN_FILENO, TCSANOW, &raw) < 0) return -1;
    printf("\033[?25l");   // hide cursor
    printf(CLEAR_SCRN);
    fflush(stdout);
    return 0;
}

static int term_restore(void) {
    printf(COL_RESET);
    printf(CLEAR_SCRN);
    printf("\033[?25h\n");  // show cursor
    if (tcsetattr(STDIN_FILENO, TCSANOW, &orig) < 0) return -1;
    return 0;
}

static void draw_sprite(Sprite *s, int col, int row) {
    for (int y = 0; y < s->h; y++) {
        if (row + y < CAR_H)     continue;
        if (row + y > GAME_ROWS) break;
        printf(GOTO, row + y, col);
        for (int x = 0; x < s->w; x++)
            printf("%s  ", s->data[y * s->w + x] ? s->color : COL_ROAD);
    }
}

static void draw(void) {
    // road
    printf("\033[H");
    for (int y = 0; y < GAME_ROWS; y++) {
        for (int x = 0; x < GAME_COLS; x++) {
            if (x == 0 || x == GAME_COLS / 2) {
                printf(COL_BORDER);
                for (int b = 0; b < BORDER_W; b++) printf(" ");
                printf(COL_ROAD);
                x += BORDER_W - 1;  // skip cells already drawn
            } else {
                printf(" ");
            }
        }
        if (y < GAME_ROWS - 1) printf("\n");
    }

    // cars
    if (g.pc.crashed) draw_sprite(&crash_sprite, g.pc.x, g.pc.y);
    else              draw_sprite(&pccar_sprite,  g.pc.x, g.pc.y);

    for (int i = 0; i < MAX_ENEMIES; i++)
        draw_sprite(&encar_sprite, g.enemies[i].x, g.enemies[i].y);

    // score
    int tens  = (g.score / 10) % 10;
    int units =  g.score % 10;
    int remaining = GAME_DURATION - g.elapsed;
    int blink_off = ((remaining <= BLINK_START) && (g.elapsed % 2));
    if (!blink_off) {
        if (tens) {
            for (int y = 0; y < 5; y++) {
                printf(GOTO, 2 + y, MID_LANE - 4);
                for (int x = 0; x < 3; x++)
                    printf("%s  ", digit_data[tens][y][x] ? COL_PCCAR : COL_ROAD);
            }
        }
        for (int y = 0; y < 5; y++) {
            printf(GOTO, 2 + y, MID_LANE + 4);
            for (int x = 0; x < 3; x++)
                printf("%s  ", digit_data[units][y][x] ? COL_PCCAR : COL_ROAD);
        }
	}
        printf(COL_RESET);
        fflush(stdout);
}

static void update(void) {
    for (int i = 0; i < MAX_ENEMIES; i++) {
        // collision detection
        if (!g.pc.crashed &&
             g.pc.x + PCAR_W > g.enemies[i].x &&
             g.pc.x          < g.enemies[i].x + ENCAR_W &&
             g.pc.y          < g.enemies[i].y + CAR_H + 1 &&
             g.pc.y + CAR_H  > g.enemies[i].y) {
            g.pc.crashed            = CRASHED_TIMER;
            g.enemies[i].speed_acc = 0;
            fire_held               = 0;
            if (snd_pipe >= 0) {           // crash burst before the freeze
                unsigned char noise[SND_CHUNK];
                for (int k = 0; k < SND_CHUNK; k++) noise[k] = rand() & 0xFF;
                write(snd_pipe, noise, SND_CHUNK);
            }
            usleep(500000);
        }
        // speed: mirrors 6502 at $FB0A‚Äď$FB20; ¬ĪSPEED_STEP/frame, 0‚ÄďSPEED_MAX
        if (fire_held) { g.enemies[i].speed_acc += SPEED_STEP; if (g.enemies[i].speed_acc > SPEED_MAX) g.enemies[i].speed_acc = SPEED_MAX; }
        else           { g.enemies[i].speed_acc -= SPEED_STEP; if (g.enemies[i].speed_acc < 0)         g.enemies[i].speed_acc = 0;         }
        // delta: mirrors $FC7B (4x LSR = >>4), min 1; gives 1‚Äď7 rows/frame
        int delta = g.enemies[i].speed_acc >> 4;
        if (!delta) delta = 1;
        g.enemies[i].y += delta;
        // lateral drift (only at speed)
        if (fire_held && ++g.enemies[i].drift_timer >= DRIFT_TICKS) {
            g.enemies[i].drift_timer = 0;
            int nx = g.enemies[i].x + g.enemies[i].dx * DX_SCALE;
            if (nx < BORDER_W + 1 || nx + ENCAR_W + 1 > GAME_COLS / 2)
                g.enemies[i].dx = -g.enemies[i].dx;
            else
                g.enemies[i].x = nx;
        }

        // respawn when enemy exits bottom
        if (g.enemies[i].y >= GAME_ROWS) {
            g.enemies[i].y  = -10;
            g.score++;  // original adds score even when crashed
            g.enemies[i].x  = rand() % (GAME_COLS / 2 - BORDER_W - ENCAR_W - SPAWN_MARGIN) + BORDER_W + SPAWN_MARGIN;
            g.enemies[i].dx = (rand() % 2) ? 1 : -1;
        }
    }
    if (g.pc.crashed) g.pc.crashed--;
}

static int handle_input(void) {
    static char held[4]  = {0};
    static int  move_sil = 0;   // silence counter for arrow keys
    static int  fire_sil = 0;   // silence counter for fire (space)

   // Collect all pending bytes into one buffer before scanning.
    // Prevents partial escape sequences split across two read() calls
    // (e.g. '\033' last byte of read N, '[C' first bytes of read N+1).
    char   all[256] = {0};
    int    total    = 0;
    char   tmp[32];
    int    n;
    while ((n = read(STDIN_FILENO, tmp, sizeof(tmp))) > 0) {
        if (total + n <= (int)sizeof(all))
            memcpy(all + total, tmp, n);
        total += n;
    }
    if (total > (int)sizeof(all)) total = (int)sizeof(all);
    int  got_space = 0;
    int  got_arrow = 0;
    char arrow[4]  = {0};

    for (int j = 0; j < total; j++) {
        if (all[j] == 'q') return -1;
        if ((all[j] == 'f' || all[j] == ' ') && !g.pc.crashed) got_space = 1;
        if (all[j] == '\033' && j + 2 < total &&
            (all[j+1] == '[' || all[j+1] == 'O')) {
            arrow[0] = '\033'; arrow[1] = '['; arrow[2] = all[j+2];
            got_arrow = 1;
            j += 2;
        }
    }

    // Sticky fire: stays held for SILENCE_LIMIT frames after last space event.
    // Needed because OS key-repeat is slower than the game loop ‚ÄĒ without this,
    // fire_held flickered 0/1/0/0/0/0/1/‚Ä¶ and speed_acc never accumulated.
    if (got_space) { fire_held = 1; fire_sil = 0; }
    else if (++fire_sil > SILENCE_LIMIT) fire_held = 0;

    // Sticky arrow: same logic, bridges the OS initial key-repeat delay (~500ms).
    if (got_arrow) { memcpy(held, arrow, 4); move_sil = 0; }
    else if (++move_sil > SILENCE_LIMIT) memset(held, 0, 4);

    if (strcmp(held, "\033[C") == 0) {
        g.pc.x += 3;
        if (g.pc.x + PCAR_W > GAME_COLS / 2) g.pc.x = GAME_COLS / 2 - PCAR_W;
    }
    if (strcmp(held, "\033[D") == 0) {
        g.pc.x -= 3;
        if (g.pc.x < BORDER_W + 2)           g.pc.x = BORDER_W + 2;
    }

    return 0;
}


static void snd_init(void) {
    int fd[2];
    if (pipe(fd) < 0) return;
    if (fork() == 0) {
        close(fd[1]);
        dup2(fd[0], STDIN_FILENO);
        int devnull = open("/dev/null", O_WRONLY);
        if (devnull >= 0) {
            dup2(devnull, STDOUT_FILENO);
            dup2(devnull, STDERR_FILENO);
            close(devnull);
        }
        execlp("aplay", "aplay", "-q", "-f", "U8", "-r", "8000", "-c", "1", NULL);
        _exit(1);
    }
    close(fd[0]);
    snd_pipe      = fd[1];
    snd_prev_score = g.score;
}

static void snd_frame(void) {
    if (snd_pipe < 0) return;
    unsigned char buf[SND_CHUNK];
    int scored   = (g.score > snd_prev_score);
    snd_prev_score = g.score;
    int crashing = (g.pc.crashed > CRASHED_TIMER - 8);  // first 8 frames

    if (scored) {
        // short 880 Hz chirp ‚ÄĒ score event
        int p = SND_RATE / 880;
        for (int i = 0; i < SND_CHUNK; i++)
            buf[i] = (i % p < p / 4) ? 210 : 46;
    } else if (crashing) {
        // descending white noise ‚ÄĒ approximates TIA crash burst
        for (int i = 0; i < SND_CHUNK; i++)
            buf[i] = rand() & 0xFF;
    } else {
        // engine: narrow-duty square wave, pitch tracks speed_acc
        // 40 Hz at rest ‚Üí 280 Hz at max; mirrors TIA AUDF/speed relationship
        int freq = 40 + (g.enemies[0].speed_acc * 240 / SPEED_MAX);
        int p    = SND_RATE / freq;
        if (p < 1) p = 1;
        for (int i = 0; i < SND_CHUNK; i++)
            buf[i] = (i % p < p / 4) ? 200 : 56;  // 25% duty = buzzier
    }
    if (write(snd_pipe, buf, SND_CHUNK) < 0) {
        close(snd_pipe);
        snd_pipe = -1;   // aplay gone; disable cleanly
    }
}

static void snd_close(void) {
    if (snd_pipe >= 0) { close(snd_pipe); snd_pipe = -1; }
}

static void show_credits(void);

int main(void) {
    srand((unsigned)time(NULL));
    snd_init();
    if (term_init() < 0) return -1;

    time_t game_start = time(NULL);

    for (int i = 0; i < MAX_ENEMIES; i++) {
        g.enemies[i].x = rand() % (GAME_COLS / 2 - BORDER_W - ENCAR_W - SPAWN_MARGIN) + BORDER_W + SPAWN_MARGIN;
        g.enemies[i].dx = (rand() % 2) ? 1 : -1;
    }
    while (g.score < 100 && g.elapsed < GAME_DURATION) {
        g.elapsed = (int)(time(NULL) - game_start);
        draw();
        update();
        snd_frame();
        if (handle_input()) break;
        struct timespec pause = {0, 66000000};  // ~66ms = ~15fps
        nanosleep(&pause, NULL);
    }

    snd_close();
    show_credits();
    if (term_restore() < 0) return -1;
    return 0;
}


